func:
msg.queries = [
  {
    producto_tipo: 'AZUCAR',
    sql: "SELECT r.id, r.remito, r.numeroremito, r.fecha, r.razonsocial, r.cuit, r.factura, r.confirmado, r.cumplido, r.importado, r.estado, r.pesoremito, r.cantidadremito, r.unidadmedida, r.patente, r.chasis, r.chofer, r.dniChofer, i.orden, CONVERT(varchar(80), i.producto) AS producto_id, i.descripcion, i.cantidad, i.unidadmedida AS item_unidadmedida, i.cantidad2, i.unidamedida2, i.precio FROM dbo.pr_ezi_remitos r LEFT JOIN dbo.pr_ezi_remitos_items i ON i.Remito = r.remito WHERE (r.factura IS NULL OR LTRIM(RTRIM(r.factura)) = '') AND ISNULL(r.estado, '') NOT IN ('ANULADO', 'Anulado', 'ANULADA', 'Anulada') ORDER BY r.fecha DESC, r.remito DESC, i.orden"
  },
  {
    producto_tipo: 'ALCOHOL',
    sql: "SELECT r.id, r.remito, r.numeroremito, r.fecha, r.razonsocial, r.cuit, r.factura, r.confirmado, r.cumplido, r.importado, r.estado, r.nroAnalisis, r.gl, r.ltsAlcohol, r.neto, r.bruto, r.pesoremito, r.cantidadremito, r.unidadmedida, r.patente, r.chasis, r.chofer, r.dniChofer, i.orden, CONVERT(varchar(80), i.producto) AS producto_id, i.descripcion, i.cantidad, i.unidadmedida AS item_unidadmedida FROM dbo.pr_ezi_remitos_alcohol r LEFT JOIN dbo.pr_ezi_remitos_alcohol_items i ON i.Remito = r.remito WHERE (r.factura IS NULL OR LTRIM(RTRIM(r.factura)) = '') AND ISNULL(r.estado, '') NOT IN ('ANULADO', 'Anulado', 'ANULADA', 'Anulada') ORDER BY r.fecha DESC, r.remito DESC, i.orden"
  }
];
return [msg.queries.map(q => ({ payload: q.sql, producto_tipo: q.producto_tipo }))];
